import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import TaskCard from '../components/TaskCard';
import AddTaskModal from '../components/AddTaskModal';
import Login from './Login';
import Signup from './Signup';
import { motion, AnimatePresence } from 'framer-motion';
import { LayoutDashboard, Clock, AlertCircle, Plus, Users } from 'lucide-react';
import axios from 'axios';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [authMode, setAuthMode] = useState(null);

  const token = localStorage.getItem('token');
  const name = localStorage.getItem('name') || 'Chief';
  const role = localStorage.getItem('role') || 'member';

  const fetchTasks = async () => {
    if (!token) return;
    try {
      const res = await axios.get('http://localhost:5000/api/tasks', {
        headers: { 'x-auth-token': token }
      });
      setTasks(res.data);
    } catch (err) {
      console.error("Fetch Error:", err);
    }
  };

  useEffect(() => {
    fetchTasks();
  }, [token]);

  const handleAuthSuccess = () => {
    setAuthMode(null);
    window.location.reload();
  };

  // Stats Logic
  const overdueCount = tasks.filter(t => t.dueDate && new Date(t.dueDate) < new Date() && t.status !== 'Completed').length;
  const completedCount = tasks.filter(t => t.status === 'Completed').length;

  return (
    <div className="min-h-screen bg-[#020617] text-white font-sans selection:bg-indigo-500/30">
      <Navbar onLoginClick={() => setAuthMode('login')} onSignupClick={() => setAuthMode('signup')} />

      {/* Auth Modals Logic */}
      <AnimatePresence>
        {authMode && (
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4"
          >
            <div className="relative w-full max-w-sm">
              <button 
                onClick={() => setAuthMode(null)} 
                className="absolute -top-12 right-0 text-white/50 hover:text-white font-bold transition-all px-4 py-2 border border-white/10 rounded-full"
              >
                ✕ CLOSE
              </button>
              {authMode === 'login' ? <Login onSuccess={handleAuthSuccess} /> : <Signup onSuccess={handleAuthSuccess} />}
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Add Task Modal */}
      <AddTaskModal isOpen={isTaskModalOpen} onClose={() => setIsTaskModalOpen(false)} refreshTasks={fetchTasks} />

      <main className="pt-32 pb-20 px-6 max-w-7xl mx-auto">
        {/* Welcome Header */}
        <header className="mb-12">
          <motion.h1 
            initial={{ opacity: 0, x: -20 }} 
            animate={{ opacity: 1, x: 0 }}
            className="text-5xl md:text-6xl font-black italic tracking-tighter uppercase"
          >
            HI, {name} 👋
          </motion.h1>
          <div className="flex items-center gap-2 mt-4">
            <span className="px-3 py-1 bg-indigo-600/20 border border-indigo-500/30 text-indigo-400 text-[10px] font-black uppercase tracking-[0.2em] rounded-md">
              {role} ACCESS
            </span>
            <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-ping"></span>
          </div>
        </header>

        {/* Bento Grid Stats */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-16">
          <div className="group p-8 bg-white/[0.03] border border-white/10 rounded-[2.5rem] hover:bg-white/[0.07] transition-all duration-500">
            <LayoutDashboard className="text-blue-400 mb-6 group-hover:scale-110 transition-transform" size={28} />
            <div className="text-5xl font-black">{token ? tasks.length : '0'}</div>
            <div className="text-gray-500 text-xs font-bold uppercase tracking-widest mt-2">Active Assignments</div>
          </div>
          
          <div className="group p-8 bg-red-500/[0.03] border border-red-500/10 rounded-[2.5rem] hover:bg-red-500/[0.07] transition-all duration-500">
            <AlertCircle className="text-red-500 mb-6 group-hover:scale-110 transition-transform" size={28} />
            <div className="text-5xl font-black text-red-500">{token ? overdueCount : '0'}</div>
            <div className="text-gray-500 text-xs font-bold uppercase tracking-widest mt-2">Critical Overdue</div>
          </div>

          <div className="group p-8 bg-green-500/[0.03] border border-green-500/10 rounded-[2.5rem] hover:bg-green-500/[0.07] transition-all duration-500">
            <Clock className="text-green-400 mb-6 group-hover:scale-110 transition-transform" size={28} />
            <div className="text-5xl font-black text-green-400">{token ? completedCount : '0'}</div>
            <div className="text-gray-500 text-xs font-bold uppercase tracking-widest mt-2">Ops Completed</div>
          </div>
        </div>

        {/* Section Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
          <div>
            <h2 className="text-3xl font-black italic tracking-tight">MISSION CONTROL</h2>
            <p className="text-gray-500 text-sm mt-1 uppercase tracking-widest font-medium">Real-time Project Tracking</p>
          </div>
          
          {token && role === 'admin' && (
            <button 
              onClick={() => setIsTaskModalOpen(true)} 
              className="group flex items-center gap-3 bg-indigo-600 hover:bg-indigo-500 px-8 py-4 rounded-2xl font-black text-sm transition-all shadow-xl shadow-indigo-500/20 active:scale-95"
            >
              <Plus size={20} className="group-hover:rotate-90 transition-transform" /> NEW DEPLOYMENT
            </button>
          )}
        </div>

        {/* Task Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {token ? (
            tasks.length > 0 ? (
              tasks.map(t => <TaskCard key={t._id} task={t} refreshTasks={fetchTasks} />)
            ) : (
              <div className="col-span-full py-24 text-center bg-white/[0.02] border border-dashed border-white/10 rounded-[3rem]">
                <p className="text-gray-600 font-bold italic">NO ACTIVE MISSIONS IN SECTOR.</p>
              </div>
            )
          ) : (
            <div className="col-span-full py-24 text-center bg-indigo-600/[0.03] border border-dashed border-indigo-500/20 rounded-[3rem]">
              <p className="text-indigo-400/60 font-black tracking-widest mb-4">ACCESS DENIED</p>
              <button 
                onClick={() => setAuthMode('login')}
                className="text-white bg-white/5 border border-white/10 px-6 py-2 rounded-xl text-xs font-bold hover:bg-white/10 transition-all"
              >
                LOGIN TO VIEW BOARD
              </button>
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
};

export default Dashboard;
